import React, { useState } from 'react';
import {
  Container,
  Grid,
  Box,
  TextField,
  Button,
  Typography,
  Paper,
  IconButton,
  Snackbar,
  Alert,
  useTheme
} from '@mui/material';
import {
  Email,
  Phone,
  GitHub,
  LinkedIn,
  Code,
  Send
} from '@mui/icons-material';
import SectionTitle from './SectionTitle';

const ContactSection = () => {
  const theme = useTheme();
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    subject: '',
    message: ''
  });
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [snackbar, setSnackbar] = useState({
    open: false,
    message: '',
    severity: 'success'
  });

  const contactInfo = [
    {
      icon: <Email color="primary" fontSize="large" />,
      title: 'Email',
      value: 'harsh160502@gmail.com',
      link: 'mailto:harsh160502@gmail.com'
    },
    {
      icon: <Phone color="primary" fontSize="large" />,
      title: 'Phone',
      value: '+91 9982346893',
      link: 'tel:+919982346893'
    },
    {
      icon: <GitHub color="primary" fontSize="large" />,
      title: 'GitHub',
      value: 'Harsh1652',
      link: 'https://github.com/Harsh1652'
    },
    {
      icon: <LinkedIn color="primary" fontSize="large" />,
      title: 'LinkedIn',
      value: 'harsh-gupta16',
      link: 'https://linkedin.com/in/harsh-gupta16'
    },
    {
      icon: <Code color="primary" fontSize="large" />,
      title: 'LeetCode',
      value: 'harsh160502',
      link: 'https://leetcode.com/harsh160502'
    }
  ];

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value
    });
    
    // Clear error when user starts typing
    if (errors[name]) {
      setErrors({
        ...errors,
        [name]: ''
      });
    }
  };

  const validate = () => {
    const newErrors = {};
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    
    if (!formData.name.trim()) {
      newErrors.name = 'Name is required';
    }
    
    if (!formData.email.trim()) {
      newErrors.email = 'Email is required';
    } else if (!emailRegex.test(formData.email)) {
      newErrors.email = 'Please enter a valid email address';
    }
    
    if (!formData.subject.trim()) {
      newErrors.subject = 'Subject is required';
    }
    
    if (!formData.message.trim()) {
      newErrors.message = 'Message is required';
    }
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!validate()) {
      return;
    }
    
    setLoading(true);
    
    // Simulate form submission
    try {
      // In a real app, this would send the form to a backend
      await new Promise(resolve => setTimeout(resolve, 1000));
      
      setSnackbar({
        open: true,
        message: 'Message sent successfully! I will get back to you soon.',
        severity: 'success'
      });
      
      // Reset form
      setFormData({
        name: '',
        email: '',
        subject: '',
        message: ''
      });
    } catch (error) {
      setSnackbar({
        open: true,
        message: 'Failed to send message. Please try again later.',
        severity: 'error'
      });
    } finally {
      setLoading(false);
    }
  };

  const handleSnackbarClose = () => {
    setSnackbar({ ...snackbar, open: false });
  };

  return (
    <Box 
      id="contact" 
      component="section" 
      sx={{ 
        py: 8,
        backgroundColor: 'background.default'
      }}
    >
      <Container>
        <SectionTitle 
          title="Get In Touch" 
          subtitle="Let's discuss your project or opportunity" 
        />
        
        <Grid container spacing={4} sx={{ mt: 2 }}>
          {/* Contact Form */}
          <Grid item xs={12} md={7}>
            <Paper 
              elevation={3} 
              sx={{ 
                p: 4, 
                backgroundColor: 'background.paper',
                borderRadius: 2
              }}
            >
              <Typography variant="h5" component="h3" gutterBottom>
                Send a Message
              </Typography>
              
              <Box component="form" noValidate onSubmit={handleSubmit} sx={{ mt: 3 }}>
                <Grid container spacing={2}>
                  <Grid item xs={12} sm={6}>
                    <TextField
                      required
                      fullWidth
                      label="Your Name"
                      name="name"
                      value={formData.name}
                      onChange={handleChange}
                      error={!!errors.name}
                      helperText={errors.name}
                    />
                  </Grid>
                  <Grid item xs={12} sm={6}>
                    <TextField
                      required
                      fullWidth
                      label="Email Address"
                      name="email"
                      value={formData.email}
                      onChange={handleChange}
                      error={!!errors.email}
                      helperText={errors.email}
                    />
                  </Grid>
                  <Grid item xs={12}>
                    <TextField
                      required
                      fullWidth
                      label="Subject"
                      name="subject"
                      value={formData.subject}
                      onChange={handleChange}
                      error={!!errors.subject}
                      helperText={errors.subject}
                    />
                  </Grid>
                  <Grid item xs={12}>
                    <TextField
                      required
                      fullWidth
                      label="Your Message"
                      name="message"
                      multiline
                      rows={4}
                      value={formData.message}
                      onChange={handleChange}
                      error={!!errors.message}
                      helperText={errors.message}
                    />
                  </Grid>
                </Grid>
                
                <Button
                  type="submit"
                  fullWidth
                  variant="contained"
                  sx={{ mt: 3, mb: 2, py: 1.5 }}
                  disabled={loading}
                  startIcon={<Send />}
                >
                  {loading ? 'Sending...' : 'Send Message'}
                </Button>
              </Box>
            </Paper>
          </Grid>
          
          {/* Contact Info */}
          <Grid item xs={12} md={5}>
            <Paper 
              elevation={3} 
              sx={{ 
                p: 4, 
                height: '100%',
                backgroundColor: 'background.paper',
                borderRadius: 2
              }}
            >
              <Typography variant="h5" component="h3" gutterBottom>
                Contact Information
              </Typography>
              
              <Box sx={{ mt: 4 }}>
                {contactInfo.map((item, index) => (
                  <Box 
                    key={index} 
                    sx={{ 
                      display: 'flex', 
                      alignItems: 'center', 
                      mb: 3,
                      '&:hover': {
                        '& .MuiTypography-root': {
                          color: 'primary.main'
                        }
                      }
                    }}
                  >
                    <IconButton 
                      component="a"
                      href={item.link}
                      target="_blank"
                      rel="noopener noreferrer"
                      sx={{ 
                        mr: 2,
                        backgroundColor: 'background.default',
                        '&:hover': {
                          backgroundColor: 'primary.dark',
                          '& .MuiSvgIcon-root': {
                            color: 'white'
                          }
                        }
                      }}
                    >
                      {item.icon}
                    </IconButton>
                    
                    <Box>
                      <Typography variant="subtitle2" color="text.secondary">
                        {item.title}
                      </Typography>
                      <Typography 
                        variant="body1" 
                        component="a"
                        href={item.link}
                        target="_blank"
                        rel="noopener noreferrer"
                        sx={{
                          textDecoration: 'none',
                          color: 'text.primary',
                          transition: 'color 0.3s',
                          '&:hover': {
                            color: 'primary.main'
                          }
                        }}
                      >
                        {item.value}
                      </Typography>
                    </Box>
                  </Box>
                ))}
              </Box>
              
              <Box sx={{ mt: 6 }}>
                <Typography variant="h6" gutterBottom>
                  Availability
                </Typography>
                <Typography variant="body2" color="text.secondary" paragraph>
                  I'm currently available for freelance work, full-time positions, or interesting project collaborations. Feel free to reach out!
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  Response time: <strong>Within 24 hours</strong>
                </Typography>
              </Box>
            </Paper>
          </Grid>
        </Grid>
      </Container>
      
      <Snackbar 
        open={snackbar.open} 
        autoHideDuration={6000} 
        onClose={handleSnackbarClose}
        anchorOrigin={{ vertical: 'bottom', horizontal: 'center' }}
      >
        <Alert 
          onClose={handleSnackbarClose} 
          severity={snackbar.severity} 
          sx={{ width: '100%' }}
        >
          {snackbar.message}
        </Alert>
      </Snackbar>
    </Box>
  );
};

export default ContactSection;
